    graphIdentifier,
    skipSnapshot,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return neptune_graph(
        "PUT",
        "/graphs/$(graphIdentifier)",
        Dict{String,Any}(
            mergewith(_merge, Dict{String,Any}("skipSnapshot" => skipSnapshot), params)
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    restore_graph_from_snapshot(graph_name, snapshot_identifier)
    restore_graph_from_snapshot(graph_name, snapshot_identifier, params::Dict{String,<:Any})

Restores a graph from a snapshot.

# Arguments

- `graph_name`: A name for the new Neptune Analytics graph to be created from the snapshot.

  The name must contain from 1 to 63 letters, numbers, or hyphens, and its first character
  must be a letter. It cannot end with a hyphen or contain two consecutive hyphens.

- `snapshot_identifier`: The ID of the snapshot in question.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"deletionProtection"`: A value that indicates whether the graph has deletion protection
  enabled. The graph can't be deleted when deletion protection is enabled.

- `"provisionedMemory"`: The provisioned memory-optimized Neptune Capacity Units (m-NCUs) to
  use for the graph.

  Min = 128

- `"publicConnectivity"`: Specifies whether or not the graph can be reachable over the
  internet. All access to graphs is IAM authenticated. (`true` to enable, or `false` to
  disable).

- `"replicaCount"`: The number of replicas in other AZs. Min =0, Max = 2, Default =1

  !!! important
      Additional charges equivalent to the m-NCUs selected for the graph apply for each
      replica.

- `"tags"`: Adds metadata tags to the snapshot. These tags can also be used with cost
  allocation reporting, or used in a Condition statement in an IAM policy.
"""
function restore_graph_from_snapshot end

function restore_graph_from_snapshot(
    graphName, snapshotIdentifier; aws_config::AbstractAWSConfig=current_aws_config()
)
    return neptune_graph(
        "POST",
        "/snapshots/$(snapshotIdentifier)/restore",
        Dict{String,Any}("graphName" => graphName);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function restore_graph_from_snapshot(
    graphName,
    snapshotIdentifier,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return neptune_graph(
        "POST",
        "/snapshots/$(snapshotIdentifier)/restore",
        Dict{String,Any}(
            mergewith(_merge, Dict{String,Any}("graphName" => graphName), params)
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    start_import_task(graph_identifier, role_arn, source)
    start_import_task(graph_identifier, role_arn, source, params::Dict{String,<:Any})

Import data into existing Neptune Analytics graph from Amazon Simple Storage Service (S3).
The graph needs to be empty and in the AVAILABLE state.

# Arguments

- `graph_identifier`: The unique identifier of the Neptune Analytics graph.
- `role_arn`: The ARN of the IAM role that will allow access to the data that is to be
  imported.
- `source`: A URL identifying the location of the data to be imported. This can be an Amazon
  S3 path, or can point to a Neptune database endpoint or snapshot.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"failOnError"`: If set to true, the task halts when an import error is encountered. If
  set to false, the task skips the data that caused the error and continues if possible.
- `"format"`: Specifies the format of Amazon S3 data to be imported. Valid values are CSV,
  which identifies the Gremlin CSV format or OPENCYPHER, which identies the openCypher load
  format.
- `"importOptions"`:
"""
function start_import_task end

function start_import_task(
    graphIdentifier, roleArn, source; aws_config::AbstractAWSConfig=current_aws_config()
)
    return neptune_graph(
        "POST",
        "/graphs/$(graphIdentifier)/importtasks",
        Dict{String,Any}("roleArn" => roleArn, "source" => source);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function start_import_task(
    graphIdentifier,
    roleArn,
    source,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return neptune_graph(
        "POST",
        "/graphs/$(graphIdentifier)/importtasks",
        Dict{String,Any}(
            mergewith(
