            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    tag_resource(resource_arn, tags)
    tag_resource(resource_arn, tags, params::Dict{String,<:Any})

Adds tags to the specified resource.

# Arguments

- `resource_arn`: ARN of the resource for which tags need to be added.

- `tags`: The tags to be assigned to the Neptune Analytics resource.

  The tags are metadata that are specified as a list of key-value pairs:

  **Key** (string) – A key is the required name of the tag. The string value can be from 1
  to 128 Unicode characters in length. It can't be prefixed with `aws:` and can only contain
  the set of Unicode characters specified by this Java regular expression:
  `"^([\\p{L}\\p{Z}\\p{N}_.:/=+\\-]*)\$")`.

  **Value** (string) – A value is the optional value of the tag. The string value can be
  from 1 to 256 Unicode characters in length. It can't be prefixed with `aws:` and can only
  contain the set of Unicode characters specified by this Java regular expression:
  `"^([\\p{L}\\p{Z}\\p{N}_.:/=+\\-]*)\$")`.
"""
function tag_resource end

function tag_resource(resourceArn, tags; aws_config::AbstractAWSConfig=current_aws_config())
    return neptune_graph(
        "POST",
        "/tags/$(resourceArn)",
        Dict{String,Any}("tags" => tags);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function tag_resource(
    resourceArn,
    tags,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return neptune_graph(
        "POST",
        "/tags/$(resourceArn)",
        Dict{String,Any}(mergewith(_merge, Dict{String,Any}("tags" => tags), params));
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

